// Fetch Users/Team Members
async function fetchUsers(event, config) {
  try {
    const {
      organization,
      project,
      personalAccessToken,
      apiVersion = '7.0'
    } = config || {};

    if (!organization || !project || !personalAccessToken) {
      throw new Error('Missing organization/project/personalAccessToken');
    }

    const baseOrg = `https://dev.azure.com/${encodeURIComponent(organization)}`;
    const baseProject = `${baseOrg}/${encodeURIComponent(project)}`;

    // Get project teams - use project-specific endpoint
    const teamsUrl = `${baseProject}/_apis/teams?api-version=${encodeURIComponent(apiVersion)}`;
    const teamsResp = await fetch(teamsUrl, {
      method: 'GET',
      redirect: 'manual',
      headers: adoHeaders(personalAccessToken)
    });

    if (!teamsResp.ok) {
      const errorText = await teamsResp.text().catch(() => '');
      console.error(`Failed to fetch teams (${teamsResp.status}):`, errorText);

      // Fallback: return empty list instead of throwing error
      // This allows the app to continue working even without user sync
      return { users: [] };
    }

