// electron/api/azuredevops.js
// Azure DevOps API proxy IPC handlers
// Migrated from server.js lines 79-537

// Helper functions
function normalizeOrgInput(orgRaw) {
  let organization = String(orgRaw || '').trim();
  if (!organization) return '';

  if (organization.includes('://')) {
    try {
      const parsed = new URL(organization);
      if (parsed.hostname === 'dev.azure.com') {
        organization = parsed.pathname.split('/').filter(Boolean)[0] || '';
      } else if (parsed.hostname.endsWith('.visualstudio.com')) {
        organization = parsed.hostname.split('.')[0] || '';
      }
    } catch (_) {
      // keep original
    }
  }
  return organization.trim();
}

function adoBaseUrl(org, project) {
  return `https://dev.azure.com/${encodeURIComponent(org)}/${encodeURIComponent(project)}/_apis`;
}

function adoHeaders(pat) {
  const auth = Buffer.from(`:${pat}`).toString('base64');
  return {
    Authorization: `Basic ${auth}`,
    Accept: 'application/json',
    // KEY: avoid redirecting to interactive AAD sign-in (HTML)
    'X-TFS-FedAuthRedirect': 'Suppress',
    // Optional but helpful
    'User-Agent': 'DevOpsDashboard/1.0'
  };
}

async function readTextSafe(resp) {
  try {
    return await resp.text();
  } catch {
    return '';
  }
}

function isLikelyHtml(ct, body) {
  const c = (ct || '').toLowerCase();
  const b = (body || '').trim().toLowerCase();
  return c.includes('text/html') || b.startsWith('<!doctype html') || b.startsWith('<html');
}

function ensureAllowedTags(tagsInput) {
  const allowed = new Set(['Grand Rapids', 'IT GR Track']);

  let tags = [];

  if (Array.isArray(tagsInput)) {
    tags = tagsInput.map(t => String(t).trim()).filter(Boolean);
  } else if (typeof tagsInput === 'string') {
    tags = tagsInput
      .split(';')
      .map(t => t.trim())
      .filter(Boolean);
  }

  // Check if at least one allowed tag exists
  const hasAllowed = tags.some(t => allowed.has(t));

  // If none present, automatically add Grand Rapids
  if (!hasAllowed) {
    tags.push('Grand Rapids');
  }

  // Remove duplicates
  tags = [...new Set(tags)];

  // Azure expects semicolon separated string
  return tags.join('; ');
}

// Sync handler
async function sync(event, config) {
  try {
    let {
      organization,
      project,
      personalAccessToken,
      apiVersion = '7.0'
    } = config || {};

    organization = normalizeOrgInput(organization);
    project = String(project || '').trim();
    personalAccessToken = String(personalAccessToken || '').trim();
    apiVersion = String(apiVersion || '7.0').trim() || '7.0';

    console.log("==== ADO SYNC DEBUG START ====");
    console.log("Config:", {
      organization,
      project,
      apiVersion,
      patLength: personalAccessToken?.length || 0
    });

    if (!organization || !project || !personalAccessToken) {
      throw new Error('Missing organization, project, or personalAccessToken');
    }

    const baseUrl = adoBaseUrl(organization, project);

    // WIQL: IDs only
    const wiqlQuery = {
      query: `
SELECT [System.Id]
FROM workitems
WHERE [System.TeamProject] = '${project.replace(/'/g, "''")}'
  AND [System.State] <> 'Removed'
ORDER BY [System.ChangedDate] DESC`
    };

    const wiqlUrl = `${baseUrl}/wit/wiql?api-version=${apiVersion}`;

    const wiqlResp = await fetch(wiqlUrl, {
      method: 'POST',
      redirect: 'manual', // KEY: don't follow redirects to sign-in pages
      headers: { ...adoHeaders(personalAccessToken), 'Content-Type': 'application/json' },
      body: JSON.stringify(wiqlQuery)
    });

    const wiqlCT = wiqlResp.headers.get('content-type') || '';
    const wiqlText = await readTextSafe(wiqlResp);

    // If redirected (302/303) you'll see it here
    if (wiqlResp.status >= 300 && wiqlResp.status < 400) {
      throw new Error(`Azure DevOps returned a redirect (likely to interactive sign-in). Status: ${wiqlResp.status}`);
    }

    if (!wiqlResp.ok) {
      throw new Error(`WIQL failed with status ${wiqlResp.status}: ${wiqlText.substring(0, 200)}`);
    }

    if (!wiqlCT.includes('application/json') || isLikelyHtml(wiqlCT, wiqlText)) {
      throw new Error('Azure DevOps returned non-JSON for WIQL (sign-in HTML or auth policy).');
    }

    const wiqlResult = JSON.parse(wiqlText);
    const ids = (wiqlResult.workItems || []).map(w => w.id);

    if (!ids.length) return { items: [] };

    // Fetch details in chunks
    const batchSize = 200;
    const all = [];

    for (let i = 0; i < ids.length; i += batchSize) {
      const batchIds = ids.slice(i, i + batchSize).join(',');
      const detUrl = `${baseUrl}/wit/workitems?ids=${batchIds}&$expand=all&api-version=${apiVersion}`;

      const detResp = await fetch(detUrl, {
        method: 'GET',
        redirect: 'manual',
        headers: adoHeaders(personalAccessToken)
      });

      const detCT = detResp.headers.get('content-type') || '';
      const detText = await readTextSafe(detResp);

      if (detResp.status >= 300 && detResp.status < 400) {
        throw new Error(`Azure DevOps details request redirected (likely to sign-in). Status: ${detResp.status}`);
      }

      if (!detResp.ok) {
        throw new Error(`Details fetch failed with status ${detResp.status}: ${detText.substring(0, 200)}`);
      }

      if (!detCT.includes('application/json') || isLikelyHtml(detCT, detText)) {
        throw new Error('Azure DevOps returned non-JSON for details (sign-in HTML or auth policy).');
      }

      const det = JSON.parse(detText);
      all.push(...(det.value || []));
    }

    console.log(`Synced ${all.length} work items`);
    return { items: all };
  } catch (error) {
    console.error('Azure DevOps sync error:', error);
    throw error;
  }
}

// Create handler
async function create(event, { config, workItem }) {
  try {
    const { organization, project, personalAccessToken, apiVersion = '7.0' } = config || {};

    if (!organization || !project || !personalAccessToken) {
      throw new Error('Missing organization/project/personalAccessToken');
    }
    if (!workItem?.title) {
      throw new Error('Missing workItem.title');
    }

    const type = encodeURIComponent(workItem.workItemType || 'Task');

    const createUrl =
      `https://dev.azure.com/${encodeURIComponent(organization)}/${encodeURIComponent(project)}` +
      `/_apis/wit/workitems/$${type}?api-version=${encodeURIComponent(apiVersion)}`;

    // Enforce required tags so it shows up in your dashboard
    const tags = ensureAllowedTags(workItem.tags);

    // JSON Patch document
    const patch = [
      { op: 'add', path: '/fields/System.Title', value: String(workItem.title) },
      { op: 'add', path: '/fields/System.Tags', value: tags }
    ];

    if (workItem.description) {
      patch.push({ op: 'add', path: '/fields/System.Description', value: String(workItem.description) });
    }
    if (workItem.areaPath) {
      patch.push({ op: 'add', path: '/fields/System.AreaPath', value: String(workItem.areaPath) });
    }
    if (workItem.priority) {
      patch.push({ op: 'add', path: '/fields/Microsoft.VSTS.Common.Priority', value: Number(workItem.priority) });
    }

    const resp = await fetch(createUrl, {
      method: 'POST',
      headers: {
        ...adoHeaders(personalAccessToken),
        'Content-Type': 'application/json-patch+json',
        Accept: 'application/json'
      },
      body: JSON.stringify(patch)
    });

    const json = await resp.json().catch(() => ({}));
    if (!resp.ok) {
      throw new Error(`Create failed: ${JSON.stringify(json).slice(0, 500)}`);
    }

    console.log(`Created work item: ${json.id}`);
    return json;
  } catch (error) {
    console.error('Azure DevOps create error:', error);
    throw error;
  }
}

// Update handler
async function update(event, { config, id, updates }) {
  try {
    const {
      organization,
      project,
      personalAccessToken,
      apiVersion = '7.0'
    } = config || {};

    if (!organization || !project || !personalAccessToken) {
      throw new Error('Missing organization/project/personalAccessToken');
    }

    const base =
      `https://dev.azure.com/${encodeURIComponent(organization)}/${encodeURIComponent(project)}`;

    const url =
      `${base}/_apis/wit/workitems/${encodeURIComponent(id)}?api-version=${encodeURIComponent(apiVersion)}`;

    const patch = [];

    // ---- Fields (use replace) ----
    if (updates?.title != null) {
      patch.push({ op: 'replace', path: '/fields/System.Title', value: String(updates.title) });
    }
    if (updates?.description != null) {
      patch.push({ op: 'replace', path: '/fields/System.Description', value: String(updates.description) });
    }
    if (updates?.state != null || updates?.status != null) {
      patch.push({
        op: 'replace',
        path: '/fields/System.State',
        value: String(updates.state ?? updates.status)
      });
    }
    if (updates?.priority != null) {
      patch.push({
        op: 'replace',
        path: '/fields/Microsoft.VSTS.Common.Priority',
        value: Number(updates.priority)
      });
    }
    if (updates?.areaPath != null) {
      patch.push({ op: 'replace', path: '/fields/System.AreaPath', value: String(updates.areaPath) });
    }

    // CMMI process: Tasks require Completion Summary when closing
    if (updates?.completionSummary != null) {
      patch.push({
        op: 'replace',
        path: '/fields/Custom.CompletionSummary',
        value: String(updates.completionSummary)
      });
    }

    // Tags (enforced)
    if (updates?.tags != null) {
      patch.push({
        op: 'replace',
        path: '/fields/System.Tags',
        value: ensureAllowedTags(updates.tags)
      });
    }

    // ---- Parent EPIC linking ----
    // Expect updates.parentId = epic work item id (number)
    if (updates?.parentId != null && String(updates.parentId).trim() !== '') {
      const epicId = Number(updates.parentId);
      if (!Number.isFinite(epicId) || epicId <= 0) {
        throw new Error('Invalid updates.parentId (epic id)');
      }

      // IMPORTANT: to remove existing parent relation we need its index.
      // We fetch current work item relations first.
      const getUrl =
        `${base}/_apis/wit/workitems/${encodeURIComponent(id)}?` +
        `api-version=${encodeURIComponent(apiVersion)}&$expand=relations`;

      const currentResp = await fetch(getUrl, {
        headers: { ...adoHeaders(personalAccessToken), Accept: 'application/json' }
      });

      const current = await currentResp.json().catch(() => ({}));
      if (!currentResp.ok) {
        throw new Error(`Failed to read work item for linking: ${JSON.stringify(current).slice(0, 500)}`);
      }

      const relations = Array.isArray(current.relations) ? current.relations : [];

      // Parent link on child = Hierarchy-Reverse
      const parentRelIndexes = relations
        .map((r, idx) => ({ r, idx }))
        .filter(x => x.r?.rel === 'System.LinkTypes.Hierarchy-Reverse');

      // remove ALL existing parents (usually only one)
      // remove from highest index to lowest so indexes don't shift
      parentRelIndexes
        .sort((a, b) => b.idx - a.idx)
        .forEach(({ idx }) => {
          patch.push({ op: 'remove', path: `/relations/${idx}` });
        });

      // add new parent relation
      const epicUrl = `${base}/_apis/wit/workitems/${encodeURIComponent(epicId)}`;
      patch.push({
        op: 'add',
        path: '/relations/-',
        value: {
          rel: 'System.LinkTypes.Hierarchy-Reverse',
          url: epicUrl,
          attributes: { comment: 'Linked to Epic from dashboard' }
        }
      });
    }

    // If nothing to patch, return friendly error
    if (patch.length === 0) {
      throw new Error('No updates provided');
    }

    const resp = await fetch(url, {
      method: 'PATCH',
      headers: {
        ...adoHeaders(personalAccessToken),
        'Content-Type': 'application/json-patch+json',
        Accept: 'application/json'
      },
      body: JSON.stringify(patch)
    });

    const json = await resp.json().catch(() => ({}));
    if (!resp.ok) {
      throw new Error(`Update failed: ${JSON.stringify(json).slice(0, 800)}`);
    }

    console.log(`Updated work item: ${id}`);
    return json;
  } catch (error) {
    console.error('Azure DevOps update error:', error);
    throw error;
  }
}

// Fetch Users/Team Members
async function fetchUsers(event, config) {
  try {
    const {
      organization,
      project,
      personalAccessToken,
      apiVersion = '7.0'
    } = config || {};

    if (!organization || !project || !personalAccessToken) {
      throw new Error('Missing organization/project/personalAccessToken');
    }

    const base = `https://dev.azure.com/${encodeURIComponent(organization)}/${encodeURIComponent(project)}`;

    // Get project teams
    const teamsUrl = `${base}/_apis/teams?api-version=${encodeURIComponent(apiVersion)}`;
    const teamsResp = await fetch(teamsUrl, {
      method: 'GET',
      redirect: 'manual',
      headers: adoHeaders(personalAccessToken)
    });

    if (!teamsResp.ok) {
      throw new Error(`Failed to fetch teams: ${teamsResp.status}`);
    }

    const teamsData = await teamsResp.json();
    const teams = teamsData.value || [];

    // Get members from all teams
    const allMembers = new Map(); // Use Map to deduplicate by unique ID

    for (const team of teams) {
      const membersUrl = `${base}/_apis/teams/${encodeURIComponent(team.id)}/members?api-version=${encodeURIComponent(apiVersion)}`;

      try {
        const membersResp = await fetch(membersUrl, {
          method: 'GET',
          redirect: 'manual',
          headers: adoHeaders(personalAccessToken)
        });

        if (membersResp.ok) {
          const membersData = await membersResp.json();
          const members = membersData.value || [];

          members.forEach(member => {
            if (member.identity) {
              allMembers.set(member.identity.id, {
                id: member.identity.id,
                displayName: member.identity.displayName,
                uniqueName: member.identity.uniqueName,
                imageUrl: member.identity.imageUrl
              });
            }
          });
        }
      } catch (err) {
        console.warn(`Failed to fetch members for team ${team.name}:`, err);
      }
    }

    const users = Array.from(allMembers.values()).sort((a, b) =>
      a.displayName.localeCompare(b.displayName)
    );

    console.log(`Fetched ${users.length} unique team members`);
    return { users };
  } catch (error) {
    console.error('Azure DevOps fetch users error:', error);
    throw error;
  }
}

// Fetch Comments/Discussions
async function fetchComments(event, { config, workItemId }) {
  try {
    const {
      organization,
      project,
      personalAccessToken,
      apiVersion = '7.0'
    } = config || {};

    if (!organization || !project || !personalAccessToken || !workItemId) {
      throw new Error('Missing required parameters');
    }

    const base = `https://dev.azure.com/${encodeURIComponent(organization)}/${encodeURIComponent(project)}`;
    const url = `${base}/_apis/wit/workItems/${encodeURIComponent(workItemId)}/comments?api-version=${encodeURIComponent(apiVersion)}`;

    const resp = await fetch(url, {
      method: 'GET',
      redirect: 'manual',
      headers: adoHeaders(personalAccessToken)
    });

    if (!resp.ok) {
      throw new Error(`Failed to fetch comments: ${resp.status}`);
    }

    const data = await resp.json();
    const comments = (data.comments || []).map(comment => ({
      id: comment.id,
      text: comment.text,
      createdBy: comment.createdBy?.displayName || 'Unknown',
      createdDate: comment.createdDate,
      modifiedDate: comment.modifiedDate
    }));

    console.log(`Fetched ${comments.length} comments for work item ${workItemId}`);
    return { comments };
  } catch (error) {
    console.error('Azure DevOps fetch comments error:', error);
    throw error;
  }
}

// Add Comment/Discussion
async function addComment(event, { config, workItemId, comment }) {
  try {
    const {
      organization,
      project,
      personalAccessToken,
      apiVersion = '7.0'
    } = config || {};

    if (!organization || !project || !personalAccessToken || !workItemId || !comment) {
      throw new Error('Missing required parameters');
    }

    const base = `https://dev.azure.com/${encodeURIComponent(organization)}/${encodeURIComponent(project)}`;
    const url = `${base}/_apis/wit/workItems/${encodeURIComponent(workItemId)}/comments?api-version=${encodeURIComponent(apiVersion)}`;

    const resp = await fetch(url, {
      method: 'POST',
      headers: {
        ...adoHeaders(personalAccessToken),
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ text: comment })
    });

    if (!resp.ok) {
      throw new Error(`Failed to add comment: ${resp.status}`);
    }

    const data = await resp.json();
    console.log(`Added comment to work item ${workItemId}`);
    return data;
  } catch (error) {
    console.error('Azure DevOps add comment error:', error);
    throw error;
  }
}

module.exports = {
  sync,
  create,
  update,
  fetchUsers,
  fetchComments,
  addComment
};
